from itertools import groupby
import re
from typing import Dict, Any

def validate_dna_sequence(
    sequence: str,
    gc_range: tuple = (40.0, 60.0),
    max_homopolymer: int = 6,
    gc_patience: int = 500                   # ← 关键参数！你说的5
) -> Dict[str, Any]:
    """
    工业级验证：允许GC短暂漂移，但不连续超标超过 patience 次
    """
    seq = sequence.upper()
    if not seq or not re.fullmatch(r'[ATCG]+', seq):
        return {"valid": False, "summary": "非法序列"}

    total = len(seq)
    gc_count = sum(1 for c in seq if c in 'CG')
    gc_percent = gc_count / total * 100

    # 同聚物检查（严格！零容忍）
    homo_lengths = [len(list(g)) for _, g in groupby(seq)]
    max_homo = max(homo_lengths) if homo_lengths else 0
    homo_ok = max_homo <= max_homopolymer

    # GC 检查（带 patience）
    gc_ok = True
    if not (gc_range[0] <= gc_percent <= gc_range[1]):
        # 我们不立即失败！而是模拟“滑动窗口”检查
        # 从头开始逐碱基检查，记录连续违规次数
        current_gc = 0
        consecutive_violation = 0
        max_consecutive = 0

        for i, base in enumerate(seq):
            if base in 'CG':
                current_gc += 1
            current_rate = current_gc / (i + 1) * 100

            if current_rate < gc_range[0] or current_rate > gc_range[1]:
                consecutive_violation += 1
                max_consecutive = max(max_consecutive, consecutive_violation)
            else:
                consecutive_violation = 0

        if max_consecutive > gc_patience:
            gc_ok = False

    passed = gc_ok and homo_ok
    failed = []
    if not gc_ok:
        failed.append(f"GC最终={gc_percent:.6f}% + 连续违规>{gc_patience}次")
    if not homo_ok:
        failed.append(f"同聚物={max_homo}>6")

    return {
        "valid": passed,
        "sequence_length": total,
        "A": seq.count('A'),
        "T": seq.count('T'),
        "C": seq.count('C'),
        "G": seq.count('G'),
        "gc_content_%": round(gc_percent, 6),
        "gc_ok": gc_ok,
        "max_homopolymer": max_homo,
        "homopolymer_ok": homo_ok,
        "max_gc_drift_streak": max_consecutive if 'max_consecutive' in locals() else 0,
        "gc_patience": gc_patience,
        "failed_constraints": failed,
        "summary": "PASS: 工业级通过（拟南芥兼容）" if passed
                  else f"FAIL: {'; '.join(failed)}"
    }


def print_validation_report(result: dict):
    print("="*80)
    print("工业级 DNA 序列验证报告（拟南芥级兼容）".center(80))
    print("="*80)
    print(f"序列长度         : {result['sequence_length']:,} bp")
    print(f"碱基分布         : A={result['A']:,} | T={result['T']:,} | C={result['C']:,} | G={result['G']:,}")
    print(f"最终GC含量       : {result['gc_content_%']:.6f}%")
    print(f"GC状态           : {'PASS' if result['gc_ok'] else 'FAIL'} "
          f"(允许短暂漂移，patience={result['gc_patience']})")
    if not result['gc_ok']:
        print(f"   └ 最长连续违规   : {result['max_gc_drift_streak']} 次")
    print(f"最长同聚物       : {result['max_homopolymer']} → {'PASS' if result['homopolymer_ok'] else 'FAIL'} (≤6)")
    print()
    print(f"最终结论         : {result['summary']}")
    print("="*80)

# 测试
if __name__ == "__main__":
    from DNAcode import DNAEncoderUltimate

    encoder = DNAEncoderUltimate(key=b"7a46677bf2d402c2")
    data = b""
    dna = encoder.encode(data)
    print(dna)
    result = validate_dna_sequence(dna)
    print_validation_report(result)
